steps.script:
var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
var unit = GameState.state["units"]["U_TD_BURNA"]
var melee_menu = 0
for w in unit["meta"]["weapons"]:
	if str(w.get("type","")).to_lower() == "melee": melee_menu += 1
return melee_menu * unit["models"].size()

var main = tree.get_root().get_node_or_null("Main")
if main == null: main = tree.current_scene
var panel = main.get_node_or_null("UnitStatsPanel")
if panel == null: return "NO_PANEL"
panel.set_collapsed(false)
panel.show_panel(true)
panel.display_unit(GameState.state["units"]["U_TD_BURNA"])
var parts = []
var stack = [panel.player_weapons_container]
while stack.size() > 0:
	var n = stack.pop_back()
	if n == null: continue
	if n is Label: parts.append(str(n.text))
	for c in n.get_children(): stack.append(c)
var txt = " || ".join(parts)
var ok = ("MELEE WEAPONS (as equipped)" in txt) and ("Cuttin' flames ×4" in txt) and ("Close combat weapon" in txt)
return "OK" if ok else ("BAD: " + txt)
